from __future__ import annotations
from pathlib import Path
from typing import Dict, Any, List
import yaml

def load_yaml(path: Path) -> Dict[str, Any]:
    if not path.exists():
        return {}
    txt = path.read_text(encoding="utf-8")
    if not txt.strip():
        return {}
    doc = yaml.safe_load(txt)
    return doc or {}

def save_yaml(path: Path, data: Dict[str, Any]) -> None:
    with path.open("w", encoding="utf-8") as f:
        yaml.safe_dump(
            data,
            f,
            sort_keys=False,
            allow_unicode=True,
            default_flow_style=True,
        )
def fmt(x: float) -> str:
    # 15 位有效数字，基本够用且不容易丢精度
    return format(float(x), ".15g")
def upsert_new_circuit_entry_with_ranges(
    cfg_path: Path,
    circuit_name: str,
    module_path: str,
    param_ranges: Dict[str, List[float]],
) -> None:
    doc = load_yaml(cfg_path)
    if not isinstance(doc, dict):
        doc = {}
    ig = doc.setdefault("instruction_generators", {})
    if not isinstance(ig, dict):
        doc["instruction_generators"] = {}
        ig = doc["instruction_generators"]
    entry = ig.setdefault(circuit_name, {})
    if not isinstance(entry, dict):
        ig[circuit_name] = {}
        entry = ig[circuit_name]
    entry.setdefault("generation_ratio", 1)
    config = entry.setdefault("config", {})
    if not isinstance(config, dict):
        entry["config"] = {}
        config = entry["config"]
    # 最小必需字段：module_path + parameters + max_turn
    config["module_path"] = module_path
    config.setdefault("max_turn", 6)
    config.setdefault("parameters", {})
    # 其它字段给默认（不覆盖已有）
    config.setdefault("use_proxy_model", False)
    config.setdefault("use_fixed_parameters", False)
    config.setdefault("fixed_parameters_rate", 0.0)
    config.setdefault("expand_target_range", False)
    config.setdefault("expand_target_range_rate", 0.0)
    config.setdefault("expand_unfixed_range", True)
    config.setdefault("expand_range_rate", [1.0, 10.0])
    config.setdefault("width_num", 0)
    config.setdefault("length_num", 0)
    config.setdefault("seed", 12345)
    config.setdefault("use_english_prompt", False)
    config.setdefault("targets", [])
    params = config["parameters"]
    if not isinstance(params, dict):
        config["parameters"] = {}
        params = config["parameters"]
    # 写入参数范围（即使为空也会写入条目）
